plt.axvline(x=140, color="red", linestyle="--",
            label="140C: Maillard starts")
plt.xlabel("Temperature (C)")
plt.ylabel("Browning rate (relative)")
plt.title("Why Hot Pans Brown Food")
plt.legend()
